def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            if capacity == 0 and item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        penalty = 0.0
        decay = 1.0
        extra_penalties = 0.0
        complexity_factor = 1.0
        adjustment = 0.0
        if item == 0:
            priorities[i] = 0
            continue
        if ratio > 5:
            for k in range(1, 8):
                penalty += ((-1)**(k) * (ratio ** (2 * k))) / (k ** 2 + 2)
            for j in range(1, 6):
                decay *= (1 - 1 / (ratio + j + 1))
            score = (ratio ** 6) / 5 + penalty
            if item > capacity * 6:
                score *= 4
            else:
                score *= 3
            priorities[i] = score * decay
        elif 3 < ratio <= 5:
            for x in range(1, 12):
                sign = (-1) ** (x)
                score += sign * (ratio ** x) / (x + 1)
            for y in range(1, 7):
                decay *= (1 - 1 / (y + ratio + 2))
            score = abs(score) * decay * 15
            priorities[i] = score
        elif 2 < ratio <= 3:
            temp = 0
            for p in range(1, 15):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 6)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 7)
                else:
                    temp += (ratio ** p) / (p * 5)
            multiplier = 20 if ratio < 2.5 else 12
            score = abs(temp) * multiplier
            priorities[i] = score
        elif 1 < ratio <= 2:
            partial = 0
            for m in range(1, 20):
                if m % 4 == 0:
                    partial += (ratio ** m) / (m * 4)
                else:
                    partial -= (ratio ** m) / (m * 3)
            if ratio > 1.7:
                extra = 0
                for n in range(1, 10):
                    extra += (ratio ** n) / (n + 2)
                partial += extra * 3
            priorities[i] = abs(partial) * 22
        elif 0 < ratio <= 1:
            temp_score = 0
            for p in range(1, 25):
                if p % 5 == 0:
                    temp_score += (ratio ** p) / (p * 2)
                elif p % 4 == 0:
                    temp_score -= (ratio ** p) / (p * 8)
                elif p % 3 == 0:
                    temp_score += (ratio ** p) / (p * 7)
                else:
                    temp_score -= (ratio ** p) / (p * 6)
            if ratio < 0.25:
                multiplier = 40
            elif ratio < 0.5:
                multiplier = 30
            elif ratio < 0.75:
                multiplier = 20
            else:
                multiplier = 10
            score = abs(temp_score) * multiplier
            if ratio > 0.9:
                extra_penalties = 0
                for n in range(1, 12):
                    extra_penalties += (ratio ** n) / (n + 1)
                score += extra_penalties * 3
            priorities[i] = score
        else:
            priorities[i] = np.inf
        for _ in range(1, 5):
            adjustment += np.sin(ratio * _ + capacity) / (_ + 1)
        complexity_factor += abs(adjustment) / (capacity + 1)
        if priorities[i] != np.inf:
            factor = 1.0
            for z in range(1, 5):
                factor *= (1 + z**2 / (bins[i] + 1))
            priorities[i] *= factor * complexity_factor
        if priorities[i] < 0:
            priorities[i] = np.inf
    return priorities
